proof fn phi_1_write_seq_idle_allows_arbitrary_read_on_missing_key(mem: PTMem, addr: usize, writes: Seq<(usize, usize)>)
    requires
        !mem.mem.dom().contains(addr),
        forall|i| 0 <= i < writes.len() ==> (#[trigger] writes[i]).0 != addr,
    ensures
        mem.write_seq(writes).read(addr) == mem.read(addr),
{
    mem.lemma_write_seq_idle(writes, addr);
}
